    if (value < 0 || value >= values.length) return null;
    return values[value];
  }
  if (value is String) {
    final normalized = value.trim();
    if (normalized.isEmpty) return null;
    final aliased = aliases[normalized] ?? normalized;
    for (final candidate in values) {
      if (candidate.name == aliased) return candidate;
    }
  }
  return null;
}

String? _widgetTypeName(Pointer<Utf8> widgetType) {
  if (widgetType.address == 0) return null;
  return widgetType.toDartString();
}

bool _matchesWidgetType(String? widgetType, String expected) {
  return widgetType == expected || widgetType == '${expected}Struct';
}

BoxShape _parseBoxShapeValue(int value) {
  return _parseEnumValue(value, BoxShape.values) ?? BoxShape.rectangle;
}

const List<Color> _transparentGradientColors = <Color>[
  Color(0x00000000),
  Color(0x00000000),
];

AlignmentGeometry _parseAlignmentGeometryValue(AlignmentGeometryStruct struct) {
  final widgetType = _widgetTypeName(struct.widgetType);
  final address = struct.handle.address;
  if (address == 0) {
    assert(() {
      debugPrint('AlignmentGeometry handle was null for $widgetType, falling back to Alignment.center');
      return true;
    }());
    return Alignment.center;
  }
  if (_matchesWidgetType(widgetType, 'Alignment')) {
    final alignment = Pointer<generated_alignment.AlignmentStruct>.fromAddress(address).ref;
    return Alignment(alignment.x, alignment.y);
  }
  if (_matchesWidgetType(widgetType, 'AlignmentDirectional')) {
    final alignment = Pointer<AlignmentDirectionalStruct>.fromAddress(address).ref;
    return AlignmentDirectional(alignment.start, alignment.y);
  }
  assert(() {
    debugPrint('Unsupported AlignmentGeometry widgetType: $widgetType, falling back to Alignment.center');
    return true;
  }());
  return Alignment.center;
}

EdgeInsetsGeometry _parseEdgeInsetsGeometryValue(EdgeInsetsGeometryStruct struct) {
  final widgetType = _widgetTypeName(struct.widgetType);
  final address = struct.handle.address;
  if (address == 0) {
    assert(() {
      debugPrint('EdgeInsetsGeometry handle was null for $widgetType, falling back to EdgeInsets.zero');
      return true;
    }());
    return EdgeInsets.zero;
  }
  if (_matchesWidgetType(widgetType, 'EdgeInsets')) {
    return parseEdgeInsets(Pointer<EdgeInsetsStruct>.fromAddress(address).ref);
  }
  if (_matchesWidgetType(widgetType, 'EdgeInsetsDirectional')) {
    final insets = Pointer<EdgeInsetsDirectionalStruct>.fromAddress(address).ref;
    return EdgeInsetsDirectional.fromSTEB(insets.start, insets.top, insets.end, insets.bottom);
  }
  assert(() {
    debugPrint('Unsupported EdgeInsetsGeometry widgetType: $widgetType, falling back to EdgeInsets.zero');
    return true;
  }());
  return EdgeInsets.zero;
}

BorderRadiusGeometry _parseBorderRadiusGeometryValue(BorderRadiusGeometryStruct struct) {
  final widgetType = _widgetTypeName(struct.widgetType);
  final address = struct.handle.address;
  if (address == 0) {
    assert(() {
      debugPrint('BorderRadiusGeometry handle was null for $widgetType, falling back to BorderRadius.zero');
      return true;
    }());
    return BorderRadius.zero;
  }
  if (_matchesWidgetType(widgetType, 'BorderRadius')) {
    return parseBorderRadius(Pointer<BorderRadiusStruct>.fromAddress(address).ref);
  }
  if (_matchesWidgetType(widgetType, 'BorderRadiusDirectional')) {
    final radius = Pointer<BorderRadiusDirectionalStruct>.fromAddress(address).ref;
    return BorderRadiusDirectional.only(
      topStart: radius.topStart.address != 0 ? parseRadius(radius.topStart.ref) : Radius.zero,
      topEnd: radius.topEnd.address != 0 ? parseRadius(radius.topEnd.ref) : Radius.zero,
      bottomStart: radius.bottomStart.address != 0 ? parseRadius(radius.bottomStart.ref) : Radius.zero,
      bottomEnd: radius.bottomEnd.address != 0 ? parseRadius(radius.bottomEnd.ref) : Radius.zero,
    );
  }
  assert(() {
    debugPrint('Unsupported BorderRadiusGeometry widgetType: $widgetType, falling back to BorderRadius.zero');
    return true;
  }());
  return BorderRadius.zero;
}

BoxDecoration _parseBoxDecorationValue(BoxDecorationStruct struct) {
  assert(() {
    final unsupported = <String>[
      if (struct.hasImage != 0 && struct.image.address != 0) 'image',
      if (struct.hasBorder != 0 && struct.border.address != 0) 'border',
      if (struct.hasBoxShadow != 0 && struct.boxShadow.address != 0) 'boxShadow',
    ];
    if (unsupported.isNotEmpty) {
      debugPrint('BoxDecoration parser is skipping unsupported fields: ${unsupported.join(', ')}');
    }
    return true;
  }());
  return BoxDecoration(
    color: struct.hasColor != 0 ? Color(struct.color) : null,
    borderRadius: struct.hasBorderRadius != 0 && struct.borderRadius.address != 0
        ? _parseBorderRadiusGeometryValue(struct.borderRadius.ref)
        : null,
    gradient: struct.hasGradient != 0 && struct.gradient.address != 0
        ? parseGradient(struct.gradient.ref)
        : null,
    backgroundBlendMode: struct.hasBackgroundBlendMode != 0
        ? parseBlendMode(struct.backgroundBlendMode)
        : null,
    shape: _parseBoxShapeValue(struct.shape),
  );
}

Decoration _parseDecorationValue(DecorationStruct struct) {
  final widgetType = _widgetTypeName(struct.widgetType);
  final address = struct.handle.address;
  if (address == 0) {
    assert(() {
      debugPrint('Decoration handle was null for $widgetType, falling back to const BoxDecoration()');
      return true;
    }());
    return const BoxDecoration();
  }
  if (_matchesWidgetType(widgetType, 'BoxDecoration')) {
    return _parseBoxDecorationValue(Pointer<BoxDecorationStruct>.fromAddress(address).ref);
  }
  if (_matchesWidgetType(widgetType, 'ShapeDecoration')) {
    final decoration = Pointer<ShapeDecorationStruct>.fromAddress(address).ref;
    assert(() {
      final unsupported = <String>[
        if (decoration.hasImage != 0 && decoration.image.address != 0) 'image',
        if (decoration.hasShadows != 0 && decoration.shadows.address != 0) 'shadows',
        if (decoration.shape.address != 0) 'shape',
      ];
      if (unsupported.isNotEmpty) {
        debugPrint('ShapeDecoration parser is skipping unsupported fields: ${unsupported.join(', ')}');
      }
      return true;
    }());
    return BoxDecoration(
      color: decoration.hasColor != 0 ? Color(decoration.color) : null,
      gradient: decoration.hasGradient != 0 && decoration.gradient.address != 0
          ? parseGradient(decoration.gradient.ref)
          : null,
    );
  }
  assert(() {
    debugPrint('Unsupported Decoration widgetType: $widgetType, falling back to const BoxDecoration()');
    return true;
  }());
  return const BoxDecoration();
}

Gradient _parseGradientValue(GradientStruct struct) {
  final widgetType = _widgetTypeName(struct.widgetType);
  final address = struct.handle.address;
  if (address == 0) {
    assert(() {
      debugPrint('Gradient handle was null for $widgetType, falling back to a transparent LinearGradient');
      return true;
    }());
    return const LinearGradient(colors: _transparentGradientColors);
  }
  if (_matchesWidgetType(widgetType, 'LinearGradient')) {
    final gradient = Pointer<LinearGradientStruct>.fromAddress(address).ref;
    assert(() {
      final unsupported = <String>[
        if (gradient.colors.address != 0) 'colors',
        if (gradient.hasStops != 0 && gradient.stops.address != 0) 'stops',
        if (gradient.tileMode.address != 0) 'tileMode',
        if (gradient.hasTransform != 0 && gradient.transform.address != 0) 'transform',
      ];
      if (unsupported.isNotEmpty) {
        debugPrint('LinearGradient parser is skipping unsupported fields: ${unsupported.join(', ')}');
      }
      return true;
    }());
    return LinearGradient(
      begin: gradient.begin.address != 0 ? parseAlignmentGeometry(gradient.begin.ref) : Alignment.centerLeft,
      end: gradient.end.address != 0 ? parseAlignmentGeometry(gradient.end.ref) : Alignment.centerRight,
      colors: _transparentGradientColors,
    );
  }
  if (_matchesWidgetType(widgetType, 'RadialGradient')) {
    final gradient = Pointer<RadialGradientStruct>.fromAddress(address).ref;
    assert(() {
      final unsupported = <String>[
        if (gradient.colors.address != 0) 'colors',
        if (gradient.hasStops != 0 && gradient.stops.address != 0) 'stops',
        if (gradient.tileMode.address != 0) 'tileMode',
        if (gradient.hasTransform != 0 && gradient.transform.address != 0) 'transform',
      ];
      if (unsupported.isNotEmpty) {
        debugPrint('RadialGradient parser is skipping unsupported fields: ${unsupported.join(', ')}');
      }
      return true;
    }());
    return RadialGradient(
      center: gradient.center.address != 0 ? parseAlignmentGeometry(gradient.center.ref) : Alignment.center,
      radius: gradient.radius > 0 ? gradient.radius : 0.5,
      focal: gradient.hasFocal != 0 && gradient.focal.address != 0 ? parseAlignmentGeometry(gradient.focal.ref) : null,
      focalRadius: gradient.focalRadius > 0 ? gradient.focalRadius : 0.0,
      colors: _transparentGradientColors,
    );
  }
  if (_matchesWidgetType(widgetType, 'SweepGradient')) {
    final gradient = Pointer<SweepGradientStruct>.fromAddress(address).ref;
    assert(() {
      final unsupported = <String>[
        if (gradient.colors.address != 0) 'colors',
        if (gradient.hasStops != 0 && gradient.stops.address != 0) 'stops',
        if (gradient.tileMode.address != 0) 'tileMode',
        if (gradient.hasTransform != 0 && gradient.transform.address != 0) 'transform',
      ];
      if (unsupported.isNotEmpty) {
        debugPrint('SweepGradient parser is skipping unsupported fields: ${unsupported.join(', ')}');
      }
      return true;
    }());
    return SweepGradient(
      center: gradient.center.address != 0 ? parseAlignmentGeometry(gradient.center.ref) : Alignment.center,
      startAngle: gradient.startAngle,
      endAngle: gradient.endAngle != 0 ? gradient.endAngle : 6.283185307179586,
      colors: _transparentGradientColors,
    );
  }
  assert(() {
    debugPrint('Unsupported Gradient widgetType: $widgetType, falling back to a transparent LinearGradient');
    return true;
  }());
  return const LinearGradient(colors: _transparentGradientColors);
}

/// Parses TextStyle from TextStyleStruct (FFI struct).
TextStyle parseTextStyleFromStruct(TextStyleStruct struct) {
  return TextStyle(
    inherit: struct.inherit == 1,
    color: struct.color != 0 ? Color(struct.color) : null,
    backgroundColor: struct.backgroundColor != 0 ? Color(struct.backgroundColor) : null,
    fontFamily: struct.fontFamily.address != 0 ? struct.fontFamily.toDartString() : null,
    fontSize: struct.fontSize > 0 ? struct.fontSize : null,
    fontWeight: struct.fontWeight >= 0 ? _parseFontWeight(struct.fontWeight) : null,
    fontStyle: struct.fontStyle >= 0 ? _parseFontStyle(struct.fontStyle) : null,
    letterSpacing: struct.letterSpacing != 0 ? struct.letterSpacing : null,
    wordSpacing: struct.wordSpacing != 0 ? struct.wordSpacing : null,
    textBaseline: struct.textBaseline >= 0 ? _parseTextBaseline(struct.textBaseline) : null,
    height: struct.height > 0 ? struct.height : null,
    decorationThickness: struct.decorationThickness > 0 ? struct.decorationThickness : null,
    debugLabel: struct.debugLabel.address != 0 ? struct.debugLabel.toDartString() : null,
  );
}

FontWeight? _parseFontWeight(int value) {
  if (value < 0 || value > 8) return null;
  return FontWeight.values[value];
}

FontStyle? _parseFontStyle(int value) {
  if (value < 0 || value > 1) return null;
  return FontStyle.values[value];
}

TextBaseline? _parseTextBaseline(int value) {
  if (value < 0 || value > 1) return null;
  return TextBaseline.values[value];
}


