// Callback Creator Functions
// ═══════════════════════════════════════════════════════════════
// These functions create Flutter callbacks that dispatch to C# via method channel.
// The actionId parameter is a string identifier for the C# action handler.


/// Invokes a C# action by its string ID via the method channel.
Future<void> _invokeAction(String? actionId, {String? widgetType, Map<String, dynamic>? args}) async {
  if (actionId == null || actionId.isEmpty) return;
  try {
    await invokeHandleAction(actionId, widgetType: widgetType, args: args);
  } catch (e) {
    print('Error invoking action $actionId: $e');
  }
}

/// Creates a VoidCallback that invokes the C# action.
VoidCallback? createVoidCallback(String? actionId) {
  if (actionId == null || actionId.isEmpty) return null;
  return () => _invokeAction(actionId);
}

/// Creates a ValueChanged<bool> callback that invokes the C# action.
ValueChanged<bool>? createValueChangedCallback(String? actionId) {
  if (actionId == null || actionId.isEmpty) return null;
  return (bool value) => _invokeAction(actionId, args: {'value': value});
}

/// Creates a ValueChanged<bool> callback (alias).
